1	// COR24 APL Interpreter -- Evaluator
2	// Tree-walking evaluator returning array heap indices.
3	// Every result is an array (scalars wrapped via arr_scalar).
4	// Supports element-wise ops on vectors with scalar extension.
5	
6	#pragma once
7	
8	// Error codes: 0=none, 1=DOMAIN, 2=VALUE, 3=LENGTH
9	int eval_err;
10	
11	// Apply a binary op to two scalars
12	int eval_binop_scalar(int op, int a, int b) {
13	    if (op == TOK_PLUS)       return a + b;
14	    if (op == TOK_MINUS)      return a - b;
15	    if (op == TOK_STAR)       return a * b;
16	    if (op == TOK_SLASH) {
17	        if (b == 0) { eval_err = 1; return 0; }
18	        return a / b;
19	    }
20	    eval_err = 1;
21	    return 0;
22	}
23	
24	// Evaluate AST node, return heap index of result array.
25	// On error, sets eval_err and returns -1.
26	int eval(int n) {
27	    if (eval_err) return -1;
28	    if (n < 0 || n >= node_count) {
29	        eval_err = 1;
30	        return -1;
31	    }
32	
33	    int ty = node_type[n];
34	
35	    if (ty == NODE_NUM) {
36	        int r = arr_scalar(node_val[n]);
37	        if (r < 0) { eval_err = 1; return -1; }
38	        return r;
39	    }
40	
41	    if (ty == NODE_VEC) {
42	        return node_val[n];
43	    }
44	
45	    if (ty == NODE_IDENT) {
46	        int idx = node_val[n];
47	        if (!sym_set_flag[idx]) {
48	            eval_err = 2;
49	            return -1;
50	        }
51	        return sym_val[idx];
52	    }
53	
54	    if (ty == NODE_ASSIGN) {
55	        int idx = node_val[n];
56	        int v = eval(node_right[n]);
57	        if (eval_err) return -1;
58	        sym_val[idx] = v;
59	        sym_set_flag[idx] = 1;
60	        return v;
61	    }
62	
63	    if (ty == NODE_QOUT) {
64	        int v = eval(node_right[n]);
65	        if (eval_err) return -1;
66	        return v;
67	    }
68	
69	    if (ty == NODE_NEG) {
70	        int v = eval(node_right[n]);
71	        if (eval_err) return -1;
72	        int rk = arr_rank(v);
73	        if (rk == 0) {
74	            int r = arr_scalar(0 - arr_get(v, 0));
75	            if (r < 0) { eval_err = 1; return -1; }
76	            return r;
77	        }
78	        // Negate each element of vector
79	        int sz = arr_size(v);
80	        int r = arr_vector(sz);
81	        if (r < 0) { eval_err = 1; return -1; }
82	        int i = 0;
83	        while (i < sz) {
84	            arr_set(r, i, 0 - arr_get(v, i));
85	            i++;
86	        }
87	        return r;
88	    }
89	
90	    if (ty == NODE_MONAD) {
91	        int v = eval(node_right[n]);
92	        if (eval_err) return -1;
93	        int res_id = node_val[n];
94	
95	        if (res_id == RES_IOTA) {
96	            // iota N: generate vector 0 1 2 ... N-1
97	            if (arr_rank(v) != 0) { eval_err = 3; return -1; }
98	            int count = arr_get(v, 0);
99	            if (count < 0) { eval_err = 1; return -1; }
100	            int r = arr_vector(count);
101	            if (r < 0) { eval_err = 1; return -1; }
102	            int i = 0;
103	            while (i < count) {
104	                arr_set(r, i, i);
105	                i++;
106	            }
107	            return r;
108	        }
109	
110	        if (res_id == RES_RHO) {
111	            // rho A: return shape of A
112	            int rk = arr_rank(v);
113	            if (rk == 0) {
114	                // Scalar: shape is empty vector
115	                int r = arr_vector(0);
116	                if (r < 0) { eval_err = 1; return -1; }
117	                return r;
118	            }
119	            if (rk == 1) {
120	                // Vector: shape is 1-element vector with length
121	                int r = arr_scalar(arr_dim0(v));
122	                if (r < 0) { eval_err = 1; return -1; }
123	                return r;
124	            }
125	            if (rk == 2) {
126	                // Matrix: shape is 2-element vector (rows cols)
127	                int r = arr_vector(2);
128	                if (r < 0) { eval_err = 1; return -1; }
129	                arr_set(r, 0, arr_dim0(v));
130	                arr_set(r, 1, arr_dim1(v));
131	                return r;
132	            }
133	            eval_err = 1;
134	            return -1;
135	        }
136	
137	        if (res_id == RES_REV) {
138	            // rev A: reverse a vector
139	            int rk = arr_rank(v);
140	            if (rk == 0) {
141	                // Scalar: reverse is identity
142	                return v;
143	            }
144	            if (rk == 1) {
145	                int sz = arr_size(v);
146	                int r = arr_vector(sz);
147	                if (r < 0) { eval_err = 1; return -1; }
148	                int i = 0;
149	                while (i < sz) {
150	                    arr_set(r, i, arr_get(v, sz - 1 - i));
151	                    i++;
152	                }
153	                return r;
154	            }
155	            eval_err = 1;
156	            return -1;
157	        }
158	
159	        if (res_id == RES_CAT) {
160	            // Monadic cat: ravel (flatten to 1D vector)
161	            int rk = arr_rank(v);
162	            if (rk == 0) {
163	                // Scalar -> 1-element vector
164	                int r = arr_vector(1);
165	                if (r < 0) { eval_err = 1; return -1; }
166	                arr_set(r, 0, arr_get(v, 0));
167	                return r;
168	            }
169	            if (rk == 1) {
170	                // Vector: already 1D, return as-is
171	                return v;
172	            }
173	            if (rk == 2) {
174	                // Matrix -> vector of all elements
175	                int sz = arr_size(v);
176	                int r = arr_vector(sz);
177	                if (r < 0) { eval_err = 1; return -1; }
178	                int i = 0;
179	                while (i < sz) {
180	                    arr_set(r, i, arr_get(v, i));
181	                    i++;
182	                }
183	                return r;
184	            }
185	            eval_err = 1;
186	            return -1;
187	        }
188	
189	        // Unknown monadic function
190	        eval_err = 1;
191	        return -1;
192	    }
193	
194	    if (ty == NODE_REDUCE) {
195	        int v = eval(node_right[n]);
196	        if (eval_err) return -1;
197	        int op = node_val[n];
198	        int rk = arr_rank(v);
199	
200	        // Scalar reduce: just return the scalar
201	        if (rk == 0) {
202	            return v;
203	        }
204	
205	        // Vector reduce: right-to-left fold
206	        if (rk == 1) {
207	            int sz = arr_size(v);
208	            if (sz == 0) { eval_err = 1; return -1; }
209	            int acc = arr_get(v, sz - 1);
210	            int i = sz - 2;
211	            while (i >= 0) {
212	                acc = eval_binop_scalar(op, arr_get(v, i), acc);
213	                if (eval_err) return -1;
214	                i--;
215	            }
216	            int r = arr_scalar(acc);
217	            if (r < 0) { eval_err = 1; return -1; }
218	            return r;
219	        }
220	
221	        // Unsupported rank
222	        eval_err = 1;
223	        return -1;
224	    }
225	
226	    if (ty == NODE_DYAD) {
227	        int lv = eval(node_left[n]);
228	        if (eval_err) return -1;
229	        int rv = eval(node_right[n]);
230	        if (eval_err) return -1;
231	        int res_id = node_val[n];
232	
233	        if (res_id == RES_RHO) {
234	            // S rho A: reshape A to shape S with cyclic fill
235	            // S is scalar -> result is vector of that length
236	            // S is 2-element vector -> result is matrix
237	            int lrk = arr_rank(lv);
238	            int new_rank;
239	            int d0;
240	            int d1;
241	
242	            if (lrk == 0) {
243	                // Scalar shape -> vector
244	                new_rank = 1;
245	                d0 = arr_get(lv, 0);
246	                d1 = 0;
247	                if (d0 < 0) { eval_err = 1; return -1; }
248	            } else if (lrk == 1) {
249	                int lsz = arr_size(lv);
250	                if (lsz == 1) {
251	                    new_rank = 1;
252	                    d0 = arr_get(lv, 0);
253	                    d1 = 0;
254	                    if (d0 < 0) { eval_err = 1; return -1; }
255	                } else if (lsz == 2) {
256	                    new_rank = 2;
257	                    d0 = arr_get(lv, 0);
258	                    d1 = arr_get(lv, 1);
259	                    if (d0 < 0 || d1 < 0) { eval_err = 1; return -1; }
260	                } else {
261	                    // Only rank 1 and 2 supported
262	                    eval_err = 1;
263	                    return -1;
264	                }
265	            } else {
266	                eval_err = 1;
267	                return -1;
268	            }
269	
270	            int r = arr_new(new_rank, d0, d1);
271	            if (r < 0) { eval_err = 1; return -1; }
272	
273	            int total = arr_size(r);
274	            int src_sz = arr_size(rv);
275	            if (src_sz == 0) { eval_err = 1; return -1; }
276	
277	            int i = 0;
278	            while (i < total) {
279	                arr_set(r, i, arr_get(rv, i % src_sz));
280	                i++;
281	            }
282	            return r;
283	        }
284	
285	        if (res_id == RES_TAKE) {
286	            // N take A: take first N elements (negative N = from end)
287	            if (arr_rank(lv) != 0) { eval_err = 1; return -1; }
288	            int count = arr_get(lv, 0);
289	            int sz = arr_size(rv);
290	            int abs_n = count;
291	            if (abs_n < 0) abs_n = 0 - abs_n;
292	            if (abs_n > sz) { eval_err = 3; return -1; }
293	
294	            int r = arr_vector(abs_n);
295	            if (r < 0) { eval_err = 1; return -1; }
296	            int start = 0;
297	            if (count < 0) start = sz - abs_n;
298	            int i = 0;
299	            while (i < abs_n) {
300	                arr_set(r, i, arr_get(rv, start + i));
301	                i++;
302	            }
303	            return r;
304	        }
305	
306	        if (res_id == RES_DROP) {
307	            // N drop A: drop first N elements (negative N = from end)
308	            if (arr_rank(lv) != 0) { eval_err = 1; return -1; }
309	            int count = arr_get(lv, 0);
310	            int sz = arr_size(rv);
311	            int abs_n = count;
312	            if (abs_n < 0) abs_n = 0 - abs_n;
313	            if (abs_n > sz) abs_n = sz;
314	
315	            int new_sz = sz - abs_n;
316	            int r = arr_vector(new_sz);
317	            if (r < 0) { eval_err = 1; return -1; }
318	            int start = abs_n;
319	            if (count < 0) start = 0;
320	            int i = 0;
321	            while (i < new_sz) {
322	                arr_set(r, i, arr_get(rv, start + i));
323	                i++;
324	            }
325	            return r;
326	        }
327	
328	        if (res_id == RES_CAT) {
329	            // Dyadic cat: catenate two arrays
330	            int lrk = arr_rank(lv);
331	            int rrk = arr_rank(rv);
332	            int lsz = arr_size(lv);
333	            int rsz = arr_size(rv);
334	            int total = lsz + rsz;
335	            int r = arr_vector(total);
336	            if (r < 0) { eval_err = 1; return -1; }
337	            int i = 0;
338	            while (i < lsz) {
339	                arr_set(r, i, arr_get(lv, i));
340	                i++;
341	            }
342	            i = 0;
343	            while (i < rsz) {
344	                arr_set(r, lsz + i, arr_get(rv, i));
345	                i++;
346	            }
347	            return r;
348	        }
349	
350	        // Unknown dyadic function
351	        eval_err = 1;
352	        return -1;
353	    }
354	
355	    if (ty == NODE_BINOP) {
356	        int lv = eval(node_left[n]);
357	        if (eval_err) return -1;
358	        int rv = eval(node_right[n]);
359	        if (eval_err) return -1;
360	
361	        int lrk = arr_rank(lv);
362	        int rrk = arr_rank(rv);
363	        int op = node_val[n];
364	
365	        // Scalar op scalar
366	        if (lrk == 0 && rrk == 0) {
367	            int result = eval_binop_scalar(op, arr_get(lv, 0), arr_get(rv, 0));
368	            if (eval_err) return -1;
369	            int r = arr_scalar(result);
370	            if (r < 0) { eval_err = 1; return -1; }
371	            return r;
372	        }
373	
374	        // Vector op vector: must match length
375	        if (lrk == 1 && rrk == 1) {
376	            int lsz = arr_size(lv);
377	            int rsz = arr_size(rv);
378	            if (lsz != rsz) { eval_err = 3; return -1; }
379	            int r = arr_vector(lsz);
380	            if (r < 0) { eval_err = 1; return -1; }
381	            int i = 0;
382	            while (i < lsz) {
383	                int val = eval_binop_scalar(op, arr_get(lv, i), arr_get(rv, i));
384	                if (eval_err) return -1;
385	                arr_set(r, i, val);
386	                i++;
387	            }
388	            return r;
389	        }
390	
391	        // Scalar op vector
392	        if (lrk == 0 && rrk == 1) {
393	            int la = arr_get(lv, 0);
394	            int rsz = arr_size(rv);
395	            int r = arr_vector(rsz);
396	            if (r < 0) { eval_err = 1; return -1; }
397	            int i = 0;
398	            while (i < rsz) {
399	                int val = eval_binop_scalar(op, la, arr_get(rv, i));
400	                if (eval_err) return -1;
401	                arr_set(r, i, val);
402	                i++;
403	            }
404	            return r;
405	        }
406	
407	        // Vector op scalar
408	        if (lrk == 1 && rrk == 0) {
409	            int ra = arr_get(rv, 0);
410	            int lsz = arr_size(lv);
411	            int r = arr_vector(lsz);
412	            if (r < 0) { eval_err = 1; return -1; }
413	            int i = 0;
414	            while (i < lsz) {
415	                int val = eval_binop_scalar(op, arr_get(lv, i), ra);
416	                if (eval_err) return -1;
417	                arr_set(r, i, val);
418	                i++;
419	            }
420	            return r;
421	        }
422	
423	        // Unsupported rank combination
424	        eval_err = 1;
425	        return -1;
426	    }
427	
428	    eval_err = 1;
429	    return -1;
430	}
